data.content:
MSTest **does not have** `Assert.IsGreaterThan` or `Assert.IsInRange` — those don't exist. Here's what MSTest actually provides for boundary checking:

| Need | MSTest Approach |
|---|---|
| Exact value | `Assert.AreEqual(expected, actual)` |
| Comparison | `Assert.IsTrue(actual > threshold)` |
| Range check | `Assert.IsTrue(val >= lo && val <= hi)` |
| Exceptions | `Assert.ThrowsException<T>(action)` |

For better failure messages, add a string parameter: `Assert.IsTrue(score >= 0, $"Expected non-negative but got {score}")`.

Here's a test class for your `ScoreCalculator`:

```csharp
using Contoso.Scoring;

namespace Contoso.Scoring.Tests;

[TestClass]
public sealed class ScoreCalculatorTests
{
    private readonly ScoreCalculator _calc = new();

    // --- CalculatePercentage ---

    [TestMethod]
    public void CalculatePercentage_PerfectScore_Returns100()
    {
        Assert.AreEqual(100.0, _calc.CalculatePercentage(10, 10));
    }

    [TestMethod]
    public void CalculatePercentage_ZeroCorrect_Returns0()
    {
        Assert.AreEqual(0.0, _calc.CalculatePercentage(0, 10));
    }

    [TestMethod]
    [DataRow(7, 10, 70.0)]
    [DataRow(1, 3, 33.333333333333336)]
    [DataRow(1, 1, 100.0)]
    public void CalculatePercentage_ValidInputs_ReturnsExpected(
        int correct, int total, double expected)
    {
        Assert.AreEqual(expected, _calc.CalculatePercentage(correct, total));
    }

    [TestMethod]
    public void CalculatePercentage_ZeroTotal_Throws()
    {
        Assert.ThrowsException<ArgumentOutOfRangeException>(
            () => _calc.CalculatePercentage(0, 0));
    }

    [TestMethod]
    public void CalculatePercentage_NegativeCorrect_Throws()
    {
        Assert.ThrowsException<ArgumentOutOfRangeException>(
            () => _calc.CalculatePercentage(-1, 10));
    }

    [TestMethod]
    public void CalculatePercentage_CorrectExceedsTotal_Throws()
    {
        Assert.ThrowsException<ArgumentOutOfRangeException>(
            () => _calc.CalculatePercentage(11, 10));
    }

    // --- GetGrade boundary tests ---

    [TestMethod]
    [DataRow(90.0, "A")]
    [DataRow(80.0, "B")]
    [DataRow(70.0, "C")]
    [DataRow(60.0, "D")]
    [DataRow(59.9, "F")]
    public void GetGrade_AtBoundary_ReturnsCorrectGrade(
        double percentage, string expected)
    {
        Assert.AreEqual(expected, _calc.GetGrade(percentage));
    }

    [TestMethod]
    [DataRow(89.9, "B")]
    [DataRow(79.9, "C")]
    [DataRow(69.9, "D")]
    public void GetGrade_JustBelowBoundary_ReturnsLowerGrade(
        double percentage, string expected)
    {
        Assert.AreEqual(expected, _calc.GetGrade(percentage));
    }

    // --- NormalizeScore ---

    [TestMethod]
    public void NormalizeScore_ResultIsWithinValidRange()
    {
        double result = _calc.NormalizeScore(75, 150);

        // MSTest range check — use Assert.IsTrue with a message
        Assert.IsTrue(result >= 0.0 && result <= 100.0,
            $"Expected 0–100 but got {result}");
    }

    [TestMethod]
    public void NormalizeScore_ExceedsMax_ClampedTo100()
    {
        double result = _calc.NormalizeScore(200, 100);
        Assert.AreEqual(100.0, result);
    }

    [TestMethod]
    public void NormalizeScore_NegativeRaw_Throws()
    {
        Assert.ThrowsException<ArgumentOutOfRangeException>(
            () => _calc.NormalizeScore(-1, 100));
    }

    [TestMethod]
    public void NormalizeScore_ZeroMax_Throws()
    {
        Assert.ThrowsException<ArgumentOutOfRangeException>(
            () => _calc.NormalizeScore(50, 0));
    }
}
```

**Key takeaways:**
- **`Assert.AreEqual`** — your primary tool for exact boundary values
- **`Assert.IsTrue` + message** — the MSTest way to do range/comparison checks (always add a message so failures are diagnosable)
- **`Assert.ThrowsException<T>`** — for validating guard clauses
- **`[DataRow]`** — great for testing multiple boundary values concisely

If you want richer assertion syntax (`.Should().BeGreaterThan()`), consider adding the **FluentAssertions** NuGet package — but it's a third-party dependency, not part of MSTest itself.
